// Service Worker for Vibe Message Push Notifications
// Auto-generated by vibe-message SDK with PWA support

const CACHE_NAME = 'relayflow-cache-v1';
const ASSETS_TO_CACHE = [
  '/',
  '/manifest.json',
  '/icon-192.png',
  '/icon-512.png',
  '/logo.png',
];

self.addEventListener('push', (event) => {
  const data = event.data ? event.data.json() : {};

  // Handle silent notifications (no UI, just data sync)
  if (data.silent) {
    event.waitUntil(
      self.clients
        .matchAll({ includeUncontrolled: true, type: 'window' })
        .then((clients) => {
          // Send silent message to all clients
          clients.forEach((client) => {
            client.postMessage({
              type: 'SILENT_MESSAGE',
              data: data.data || {},
            });
          });
        }),
    );
    return;
  }

  // Check if any client window is focused (app is visible)
  event.waitUntil(
    self.clients
      .matchAll({ includeUncontrolled: true, type: 'window' })
      .then((clients) => {
        const focusedClient = clients.find(
          (client) => client.visibilityState === 'visible' || client.focused,
        );

        if (focusedClient) {
          // App is visible - send raw payload to foreground handler (it parses JSON itself)
          focusedClient.postMessage({
            type: 'FOREGROUND_MESSAGE',
            payload: {
              title: data.title || 'Notification',
              body: data.body || '',
              icon: data.icon || '/icon.png',
              data: data.data || {},
            },
          });
        } else {
          // App is not visible - show OS push notification
          const displayBody = data.body || '';
          const meta = data.data || {};

          const title = data.title || 'Notification';
          const options = {
            body: displayBody,
            icon: data.icon || '/icon.png',
            image: data.image,
            badge: '/badge.png',
            data: {
              click_action: data.click_action || '/',
              ...meta,
            },
            requireInteraction: false,
            tag: 'vibe-message-notification',
          };

          return self.registration.showNotification(title, options);
        }
      }),
  );
});

self.addEventListener('notificationclick', (event) => {
  event.notification.close();

  const urlToOpen = event.notification.data?.click_action || '/';
  // Resolve relative URLs to absolute URLs using the service worker's origin
  const absoluteUrl = new URL(urlToOpen, self.location.origin).href;

  event.waitUntil(
    self.clients
      .matchAll({ type: 'window', includeUncontrolled: true })
      .then((clientList) => {
        // 1. Try to find a client tab that is already on the exact target URL
        for (const client of clientList) {
          if (client.url === absoluteUrl && 'focus' in client) {
            client.postMessage({
              type: 'BACKGROUND_MESSAGE',
              payload: event.notification.data,
            });
            return client.focus();
          }
        }

        // 2. Otherwise, find any client tab belonging to our origin/site
        for (const client of clientList) {
          if (
            client.url.startsWith(self.location.origin) &&
            'focus' in client &&
            'navigate' in client
          ) {
            client.postMessage({
              type: 'BACKGROUND_MESSAGE',
              payload: event.notification.data,
            });
            client.focus();
            return client.navigate(absoluteUrl);
          }
        }

        // 3. If no client tab exists at all under our origin, open a new window
        if (self.clients.openWindow) {
          return self.clients.openWindow(absoluteUrl).then((client) => {
            if (client) {
              client.postMessage({
                type: 'BACKGROUND_MESSAGE',
                payload: event.notification.data,
              });
            }
          });
        }
      }),
  );
});

self.addEventListener('install', (event) => {
  event.waitUntil(
    caches.open(CACHE_NAME).then((cache) => {
      return cache.addAll(ASSETS_TO_CACHE);
    }),
  );
  self.skipWaiting();
});

self.addEventListener('activate', (event) => {
  event.waitUntil(
    caches
      .keys()
      .then((cacheNames) => {
        return Promise.all(
          cacheNames.map((cacheName) => {
            if (cacheName !== CACHE_NAME) {
              return caches.delete(cacheName);
            }
          }),
        );
      })
      .then(() => self.clients.claim()),
  );
});

self.addEventListener('fetch', (event) => {
  const url = new URL(event.request.url);
  const isSelfOrigin = url.origin === self.location.origin;

  // Skip non-GET requests and non-local requests
  if (event.request.method !== 'GET' || !isSelfOrigin) {
    return;
  }

  // Exclude WebSockets, API calls, dynamic socket.io, and Next.js dev HMR paths
  if (
    url.pathname.startsWith('/api/') ||
    url.pathname.includes('/socket.io') ||
    url.pathname.includes('/_next/webpack-hmr') ||
    url.pathname.includes('hot-update') ||
    url.pathname.startsWith('/_next/data/')
  ) {
    return;
  }

  event.respondWith(
    caches.match(event.request).then((cachedResponse) => {
      if (cachedResponse) {
        // Return cached response, fetch in background to update cache (Stale-While-Revalidate)
        fetch(event.request)
          .then((networkResponse) => {
            if (networkResponse.status === 200) {
              caches
                .open(CACHE_NAME)
                .then((cache) => cache.put(event.request, networkResponse));
            }
          })
          .catch(() => {});
        return cachedResponse;
      }

      return fetch(event.request)
        .then((networkResponse) => {
          if (networkResponse.status === 200) {
            const responseToCache = networkResponse.clone();
            caches.open(CACHE_NAME).then((cache) => {
              cache.put(event.request, responseToCache);
            });
          }
          return networkResponse;
        })
        .catch((err) => {
          if (event.request.mode === 'navigate') {
            return caches.match('/');
          }
          return Promise.reject(err);
        });
    }),
  );
});
